import{_ as s,o as e,c as a,ag as t}from"./chunks/framework.Dn0B0GT3.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"internals/architecture.md","filePath":"internals/architecture.md"}'),i={name:"internals/architecture.md"};function r(o,n,l,p,c,d){return e(),a("div",null,[...n[0]||(n[0]=[t(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>This page documents the internal architecture of ShellPort, explaining the directory structure, component responsibilities, and the data flow between browser, server, and PTY.</p><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><p>ShellPort is organized into a minimal, zero-dependency codebase (~2,400 lines total):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── index.ts          # CLI entry — argument parsing &amp; routing</span></span>
<span class="line"><span>├── server.ts         # HTTP + WebSocket + PTY server (Bun.serve)</span></span>
<span class="line"><span>├── client.ts         # CLI WebSocket client (raw terminal mode)</span></span>
<span class="line"><span>├── crypto.ts         # AES-256-GCM engine (PBKDF2 key derivation)</span></span>
<span class="line"><span>├── totp.ts           # TOTP 2FA (RFC 6238) — secret, QR, verify</span></span>
<span class="line"><span>├── qr.ts             # QR code generator (terminal-rendered)</span></span>
<span class="line"><span>├── types.ts          # TypeScript types, constants, SeqQueue</span></span>
<span class="line"><span>├── bounds.test.ts    # Input bounds validation tests</span></span>
<span class="line"><span>├── crypto.test.ts    # Cryptographic operation tests</span></span>
<span class="line"><span>├── index.test.ts     # CLI argument parsing tests</span></span>
<span class="line"><span>├── integration.test.ts # End-to-end flow tests</span></span>
<span class="line"><span>├── pty.test.ts       # PTY handling tests</span></span>
<span class="line"><span>├── qr.test.ts        # QR code generation tests</span></span>
<span class="line"><span>├── server.test.ts    # Server operation tests</span></span>
<span class="line"><span>├── server_ratelimit.test.ts # Rate limiting tests</span></span>
<span class="line"><span>└── totp.test.ts      # TOTP verification tests</span></span></code></pre></div><h3 id="frontend-directory" tabindex="-1">Frontend Directory <a class="header-anchor" href="#frontend-directory" aria-label="Permalink to &quot;Frontend Directory&quot;">​</a></h3><p>The frontend is bundled as a single HTML file with no external dependencies:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/frontend/</span></span>
<span class="line"><span>├── index.html    # HTML shell (entry point)</span></span>
<span class="line"><span>├── styles.css    # Terminal + sidebar UI styles</span></span>
<span class="line"><span>├── nanoterm/     # NanoTermV2 standalone terminal library</span></span>
<span class="line"><span>│   ├── index.js           # NanoTermV2 terminal emulator</span></span>
<span class="line"><span>│   ├── canvas-renderer.js # Canvas2D backend renderer</span></span>
<span class="line"><span>│   └── constants.js       # Palettes, layout, utilities</span></span>
<span class="line"><span>├── app.js        # Session manager &amp; UI logic</span></span>
<span class="line"><span>├── bundle.ts     # NanoTermV2 ES module bundler</span></span>
<span class="line"><span>└── build.ts      # HTML assembler (inlines all assets)</span></span></code></pre></div><h2 id="component-responsibilities" tabindex="-1">Component Responsibilities <a class="header-anchor" href="#component-responsibilities" aria-label="Permalink to &quot;Component Responsibilities&quot;">​</a></h2><h3 id="core-server-server-ts" tabindex="-1">Core Server (<code>server.ts</code>) <a class="header-anchor" href="#core-server-server-ts" aria-label="Permalink to &quot;Core Server (\`server.ts\`)&quot;">​</a></h3><p>The server is built on Bun&#39;s native APIs and handles:</p><ul><li><strong>HTTP Server</strong> — Serves the frontend HTML, CSS, and JavaScript bundles</li><li><strong>WebSocket Server</strong> — Manages persistent bidirectional connections with clients</li><li><strong>PTY Management</strong> — Spawns and manages pseudo-terminal processes (Bun&#39;s native <code>Bun.spawn</code> with PTY)</li><li><strong>Connection Approval</strong> — Interactive prompts for approving new connections</li><li><strong>Rate Limiting</strong> — Protects against brute-force attacks (5 attempts/IP/minute)</li><li><strong>Session Management</strong> — Tracks up to 10 concurrent PTY sessions</li></ul><h3 id="cryptographic-engine-crypto-ts" tabindex="-1">Cryptographic Engine (<code>crypto.ts</code>) <a class="header-anchor" href="#cryptographic-engine-crypto-ts" aria-label="Permalink to &quot;Cryptographic Engine (\`crypto.ts\`)&quot;">​</a></h3><p>Handles all encryption operations:</p><ul><li><strong>Key Derivation</strong> — PBKDF2 with 100,000 iterations using SHA-256</li><li><strong>Encryption</strong> — AES-256-GCM authenticated encryption</li><li><strong>Nonce Management</strong> — 12-byte random IV per message</li><li><strong>Salt Generation</strong> — Per-session cryptographic salt from server and client nonces</li><li><strong>Proof-of-Knowledge</strong> — Mutual nonce exchange for authentication</li></ul><h3 id="totp-authentication-totp-ts" tabindex="-1">TOTP Authentication (<code>totp.ts</code>) <a class="header-anchor" href="#totp-authentication-totp-ts" aria-label="Permalink to &quot;TOTP Authentication (\`totp.ts\`)&quot;">​</a></h3><p>Implements RFC 6238 time-based one-time passwords:</p><ul><li><strong>Secret Generation</strong> — RFC 6238 compliant secret creation</li><li><strong>Code Generation</strong> — SHA-1 based 6-digit TOTP (30-second window)</li><li><strong>QR Code Rendering</strong> — Terminal-rendered QR codes for authenticator pairing</li><li><strong>Secret Persistence</strong> — Saves paired secrets to <code>~/.shellport-totp-secret</code></li><li><strong>Verification</strong> — Validates TOTP codes with a ±1 window for clock drift</li></ul><h3 id="nanotermv2-terminal-frontend-nanoterm" tabindex="-1">NanoTermV2 Terminal (<code>frontend/nanoterm/</code>) <a class="header-anchor" href="#nanotermv2-terminal-frontend-nanoterm" aria-label="Permalink to &quot;NanoTermV2 Terminal (\`frontend/nanoterm/\`)&quot;">​</a></h3><p>A custom Canvas2D terminal emulator:</p><ul><li><strong>Canvas2D Rendering</strong> — Hardware-accelerated, zero DOM nodes</li><li><strong>Escape Sequence Parsing</strong> — VT100/VT220/xterm compatibility</li><li><strong>256-Color Support</strong> — Full palette + truecolor (24-bit) support</li><li><strong>Mouse Tracking</strong> — X10, Normal, and SGR modes</li><li><strong>Text Selection</strong> — With clipboard integration (OSC 52)</li><li><strong>Bracketed Paste Mode</strong> — Safe bulk text input</li><li><strong>Alternate Screen Buffer</strong> — vim, htop, tmux support</li></ul><h3 id="frontend-application-frontend-app-js" tabindex="-1">Frontend Application (<code>frontend/app.js</code>) <a class="header-anchor" href="#frontend-application-frontend-app-js" aria-label="Permalink to &quot;Frontend Application (\`frontend/app.js\`)&quot;">​</a></h3><p>Manages the browser-side session:</p><ul><li><strong>Session Initialization</strong> — Handles the WebSocket handshake</li><li><strong>Key Derivation</strong> — Derives encryption keys from URL fragment secret</li><li><strong>Terminal Integration</strong> — Bridges NanoTermV2 with WebSocket messages</li><li><strong>UI Management</strong> — Sidebar tabs, connection status, error handling</li><li><strong>Clipboard Operations</strong> — OSC 52 clipboard read/write with confirmation</li></ul><h3 id="cli-entry-index-ts" tabindex="-1">CLI Entry (<code>index.ts</code>) <a class="header-anchor" href="#cli-entry-index-ts" aria-label="Permalink to &quot;CLI Entry (\`index.ts\`)&quot;">​</a></h3><p>Provides the command-line interface:</p><ul><li><strong>Argument Parsing</strong> — Routes commands (<code>server</code>, <code>client</code>) and flags</li><li><strong>Server Startup</strong> — Initializes server with configured security mode</li><li><strong>Client Connection</strong> — Establishes WebSocket connections to remote servers</li><li><strong>Security Modes</strong> — <code>--no-secret</code>, <code>--no-totp</code>, <code>--no-approval</code>, etc.</li></ul><h2 id="data-flow-diagram" tabindex="-1">Data Flow Diagram <a class="header-anchor" href="#data-flow-diagram" aria-label="Permalink to &quot;Data Flow Diagram&quot;">​</a></h2><p>The following diagram illustrates the complete connection lifecycle, showing how data moves between the browser, server, and PTY process:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                  BROWSER                                      │</span></span>
<span class="line"><span>│  ┌─────────────────┐    ┌──────────────────┐    ┌─────────────────────────┐   │</span></span>
<span class="line"><span>│  │   NanoTermV2    │◀──▶│   Session Mgr    │◀──▶│    WebSocket Client     │   │</span></span>
<span class="line"><span>│  │  (Canvas2D)     │    │    (app.js)      │    │                         │   │</span></span>
<span class="line"><span>│  └────────┬────────┘    └────────┬─────────┘    └────────────┬────────────┘   │</span></span>
<span class="line"><span>│           │                       │                            │                │</span></span>
<span class="line"><span>│           │                       │   ┌──────────────────────┐ │                │</span></span>
<span class="line"><span>│           │                       └──▶│  Key Derivation       │◀┘                │</span></span>
<span class="line"><span>│           │                           │  (PBKDF2 + Nonces)    │                   │</span></span>
<span class="line"><span>│           │                           └──────────────────────┘                   │</span></span>
<span class="line"><span>│           │                                    │                                │</span></span>
<span class="line"><span>│           │          AES-256-GCM               │                                │</span></span>
<span class="line"><span>│           │         [iv][ciphertext]           │                                │</span></span>
<span class="line"><span>└───────────┼────────────────────────────────────┼────────────────────────────────┘</span></span>
<span class="line"><span>            │                                    │</span></span>
<span class="line"><span>            │         WebSocket (binary)          │</span></span>
<span class="line"><span>            │        ┌──────────────┐            │</span></span>
<span class="line"><span>            └───────▶│              │◀───────────┘</span></span>
<span class="line"><span>                     │              │</span></span>
<span class="line"><span>            ┌────────│              │───────────┐</span></span>
<span class="line"><span>            │        └──────────────┘           │</span></span>
<span class="line"><span>            │                                    │</span></span>
<span class="line"><span>            ▼                                    ▼</span></span>
<span class="line"><span>┌───────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                              SERVER                                           │</span></span>
<span class="line"><span>│  ┌────────────────┐    ┌─────────────────┐    ┌────────────────────────────┐  │</span></span>
<span class="line"><span>│  │  Rate Limiter  │───▶│ WebSocket       │───▶│  PTY Manager               │  │</span></span>
<span class="line"><span>│  │  (5/IP/min)    │    │  Handler        │    │  (Bun.spawn)               │  │</span></span>
<span class="line"><span>│  └────────────────┘    └────────┬────────┘    └─────────────┬──────────────┘  │</span></span>
<span class="line"><span>│                                  │                      │                      │</span></span>
<span class="line"><span>│                                  ▼                      ▼                      │</span></span>
<span class="line"><span>│                    ┌────────────────────────┐   ┌───────────────┐           │</span></span>
<span class="line"><span>│                    │  Crypto Engine          │   │ Shell Process │           │</span></span>
<span class="line"><span>│                    │  (AES-256-GCM)         │   │ (bash, zsh)   │           │</span></span>
<span class="line"><span>│                    └────────────────────────┘   └───────────────┘           │</span></span>
<span class="line"><span>│                                  │                      │                      │</span></span>
<span class="line"><span>│                                  ▼                      │                      │</span></span>
<span class="line"><span>│                    ┌────────────────────────┐           │                      │</span></span>
<span class="line"><span>│                    │  TOTP Verifier        │           │                      │</span></span>
<span class="line"><span>│                    │  (RFC 6238)           │           │                      │</span></span>
<span class="line"><span>│                    └────────────────────────┘           │                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                                    │</span></span>
<span class="line"><span>                                    ▼</span></span>
<span class="line"><span>                    ┌─────────────────────────────┐</span></span>
<span class="line"><span>                    │       PTY Process           │</span></span>
<span class="line"><span>                    │   (Pseudo Terminal)         │</span></span>
<span class="line"><span>                    │                             │</span></span>
<span class="line"><span>                    │   stdin ←─ terminal input  │</span></span>
<span class="line"><span>                    │   stdout ─── terminal      │</span></span>
<span class="line"><span>                    │         output             │</span></span>
<span class="line"><span>                    └─────────────────────────────┘</span></span></code></pre></div><h3 id="connection-flow-steps" tabindex="-1">Connection Flow Steps <a class="header-anchor" href="#connection-flow-steps" aria-label="Permalink to &quot;Connection Flow Steps&quot;">​</a></h3><ol><li><p><strong>Server Nonce Exchange</strong></p><ul><li>Server generates a random nonce and sends it to the client</li><li>Client incorporates this nonce into the key derivation salt</li></ul></li><li><p><strong>Client Nonce Exchange</strong></p><ul><li>Client generates its own random nonce and sends it to the server</li><li>Combined with server nonce and URL fragment secret, the session key is derived via PBKDF2</li></ul></li><li><p><strong>Proof-of-Knowledge</strong></p><ul><li>Server encrypts a challenge with the derived key</li><li>Client must decrypt and return it to prove key possession</li><li>This verifies both parties have the correct secret</li></ul></li><li><p><strong>TOTP Challenge</strong> <em>(if enabled)</em></p><ul><li>Server sends a TOTP challenge request</li><li>Client displays the code prompt to the user</li><li>User enters their authenticator code</li><li>Server verifies against RFC 6238 TOTP</li></ul></li><li><p><strong>Connection Approval</strong> <em>(if enabled)</em></p><ul><li>Server displays an interactive prompt to the terminal</li><li>Operator must approve the connection</li><li>Connection is rejected if denied or timeout</li></ul></li><li><p><strong>WebSocket Binary Framing</strong></p><ul><li>All terminal data is framed as binary WebSocket messages</li><li>Each frame: <code>[12-byte IV][AES-256-GCM ciphertext]</code></li><li>IV is randomly generated per message for semantic security</li></ul></li><li><p><strong>PTY Streaming</strong></p><ul><li>Server reads from PTY stdout and sends to client</li><li>Client sends user input to server, which writes to PTY stdin</li><li>Terminal resize events forwarded bidirectionally</li></ul></li></ol><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><ul><li><strong>Secret in URL Fragment</strong> — The encryption secret travels in the URL fragment (<code>#secret</code>), which is never sent to the server via HTTP headers</li><li><strong>Origin Validation</strong> — WebSocket connections validate origin; localhost bypass requires <code>--dev</code> flag</li><li><strong>Buffer Limits</strong> — OSC/DCS sequences capped at 64KB to prevent memory exhaustion attacks</li><li><strong>Safe Environment</strong> — Only whitelisted environment variables passed to the PTY</li></ul>`,34)])])}const u=s(i,[["render",r]]);export{h as __pageData,u as default};
